import React,{useEffect,useMemo,useState}from"react";import{FileText,Search,UploadCloud}from"lucide-react";import{vendorAPI,formatDate,money,safeArray}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import Modal from"../../components/ui/Modal.jsx";import{CardPanel,DetailsGrid,PageHeader,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorQuotesPage(){const{showToast}=useToast();const[quotes,setQuotes]=useState([]);const[keyword,setKeyword]=useState("");const[selected,setSelected]=useState(null);const load=async()=>{try{setQuotes(safeArray(await vendorAPI.quotes()))}catch(e){showToast(e.message,"error")}};useEffect(()=>{load()},[]);const rows=useMemo(()=>quotes.filter(q=>[q.move?.job_id,q.quote_amount,q.status,q.insurance_summary].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())),[quotes,keyword]);const withdraw=async(q)=>{try{await vendorAPI.withdrawQuote(q.id);showToast("Quote withdrawn");load()}catch(e){showToast(e.message,"error")}};return <div className="page-wrap"><PageHeader icon={FileText} title="Quotes" subtitle="Manual quote upload, confirmation and pricing management." search={keyword} onSearch={setKeyword} placeholder="Search quotes..."/><div className="content-grid-wide"><CardPanel title="Submitted Quotes"><div className="table-scroll"><table><thead><tr><th>Quote ID</th><th>Job ID</th><th>Amount</th><th>Status</th><th>Updated</th><th>Actions</th></tr></thead><tbody>{rows.map(q=><tr key={q.id}><td><b>QUOTE-{q.id}</b></td><td>{q.move?.job_id||`ANQ-${q.move_request_id}`}</td><td>{money(q.quote_amount)}</td><td><StatusPill value={q.status}/></td><td>{formatDate(q.updated_at||q.created_at)}</td><td className="row-actions"><button className="tiny-btn" onClick={()=>setSelected(q)}>View</button>{!["withdrawn","selected","rejected"].includes(q.status)?<button className="tiny-btn red-text" onClick={()=>withdraw(q)}>Withdraw</button>:null}</td></tr>)}</tbody></table>{!rows.length?<div className="empty-state">No quotes found.</div>:null}</div></CardPanel><CardPanel title="Quote Actions" subtitle="Confirm availability and pricing."><div className="details-clean-grid"><b>Manual Quote PDF</b><span><UploadCloud size={14}/>Upload from new lead action</span><b>Confirm Availability</b><span>Vendor can confirm availability for request</span><b>Confirm Pricing</b><span>Vendor can update and send final pricing</span><b>Customer Lock-in</b><span>Customer pays £50 to lock in</span></div></CardPanel></div><Modal open={!!selected} title="Quote Details" onClose={()=>setSelected(null)} size="lg"><DetailsGrid rows={[["Quote ID",`QUOTE-${selected?.id||""}`],["Job ID",selected?.move?.job_id],["Amount",money(selected?.quote_amount)],["Availability",formatDate(selected?.availability_from)],["Insurance",selected?.insurance_summary],["Movers",selected?.number_of_movers],["Van",selected?.van_details],["Status",selected?.status],["Notes",selected?.additional_notes]]}/></Modal></div>}
